"use client";

import Link from "next/link";
import { useEffect, useState } from "react";
import { ChevronLeft, Search, ShieldCheck, Users } from "lucide-react";

import { Button } from "@/components/ui/button";
import { ActionMenu } from "@/components/ui/action-menu";
import { Input } from "@/components/ui/input";
import { useConfirmation } from "@/contexts/ConfirmationContext";
import { useNotificationContext } from "@/contexts/NotificationContext";

type Coach = {
  id: string;
  name: string;
  email: string;
  requestStatus: "PENDING" | "ACCEPTED" | "REJECTED" | null;
};

const statusLabel: Record<NonNullable<Coach["requestStatus"]>, string> = {
  PENDING: "Bekliyor",
  ACCEPTED: "Kabul Edildi",
  REJECTED: "Reddedildi"
};

export default function ClientCoachesContent() {
  const { push } = useNotificationContext();
  const { confirm } = useConfirmation();
  const [search, setSearch] = useState("");
  const [coaches, setCoaches] = useState<Coach[]>([]);
  const [loadingCoachId, setLoadingCoachId] = useState<string | null>(null);

  const load = async () => {
    const query = search ? `?q=${encodeURIComponent(search)}` : "";
    const res = await fetch(`/api/client/coaches${query}`);
    const data = await res.json();
    setCoaches(data.coaches || []);
  };

  useEffect(() => {
    load();
  }, []);

  const requestCoach = async (coachId: string) => {
    setLoadingCoachId(coachId);
    const response = await fetch("/api/client/coaches/request", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ coachId })
    });
    setLoadingCoachId(null);

    if (!response.ok) {
      push("Coach iste-ƒi g+Ânderilemedi.");
      return;
    }

    push("Coach iste-ƒi g+Ânderildi.");
    await load();
  };

  const disconnectCoach = async (coachId: string) => {
    const approved = await confirm({
      title: "Coach baglantisini kaldir",
      description: "Bu coach ile baglantiyi kaldirmak istediginize emin misiniz?",
      confirmText: "Kaldir",
      cancelText: "Vazgec",
      danger: true
    });

    if (!approved) {
      return;
    }

    setLoadingCoachId(coachId);
    const response = await fetch(`/api/client/coaches/${coachId}`, {
      method: "DELETE"
    });
    const data = await response.json().catch(() => ({}));
    setLoadingCoachId(null);

    if (!response.ok) {
      push(data.error || "Coach ba-ƒlant-¦s-¦ kald-¦r-¦lamad-¦.");
      return;
    }

    push("Coach ba-ƒlant-¦s-¦ kald-¦r-¦ld-¦.");
    await load();
  };

  return (
    <div className="space-y-4 md:space-y-5">
      <section className="overflow-hidden rounded-2xl border border-emerald-200/60 bg-gradient-to-br from-emerald-50 via-white to-lime-50 p-4 shadow-sm md:rounded-[28px] md:p-6">
        <Link
          href="/client/dashboard"
          className="inline-flex items-center gap-2 text-xs font-medium text-emerald-700 hover:text-emerald-900 md:text-sm"
        >
          <ChevronLeft className="h-4 w-4" />
          Dashboard'a geri d+Ân
        </Link>
        <div className="mt-3 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
          <div>
            <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-emerald-700 md:text-xs">Coach Network</p>
            <h1 className="mt-1 text-2xl font-black tracking-tight text-slate-900 md:text-3xl">Coach Bul</h1>
            <p className="mt-1 text-xs text-slate-600 md:text-sm">Coach ara, istek g+Ânder ve mevcut ba-ƒlant-¦lar-¦n-¦ y+Ânet.</p>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div className="rounded-xl bg-white px-3 py-2 shadow-sm">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500">Toplam</p>
              <p className="mt-1 text-lg font-black text-slate-900">{coaches.length}</p>
            </div>
            <div className="rounded-xl bg-white px-3 py-2 shadow-sm">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500">Kabul</p>
              <p className="mt-1 text-lg font-black text-emerald-700">{coaches.filter((coach) => coach.requestStatus === "ACCEPTED").length}</p>
            </div>
          </div>
        </div>
      </section>

      <div className="rounded-2xl border bg-card p-3 md:p-4">
        <div className="flex flex-col gap-2 sm:flex-row">
          <div className="relative flex-1">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="-¦sme g+Âre ara"
              className="pl-9"
            />
          </div>
          <Button type="button" onClick={load} className="w-full sm:w-auto">
            Ara
          </Button>
        </div>
      </div>

      <div className="space-y-2.5 md:space-y-3">
        {coaches.length === 0 ? (
          <div className="rounded-xl border border-dashed p-6 text-sm text-muted-foreground">
            Arama kriterine uygun coach bulunamad-¦.
          </div>
        ) : (
          coaches.map((coach) => (
            <div key={coach.id} className="rounded-2xl border p-3.5 shadow-sm md:p-4">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <Users className="h-4 w-4 text-emerald-600" />
                    <p className="line-clamp-1 text-sm font-semibold md:text-base">{coach.name}</p>
                  </div>
                  <p className="mt-1 line-clamp-1 text-xs text-muted-foreground">{coach.email}</p>
                  <p className="mt-2 inline-flex items-center gap-1 rounded-full px-2.5 py-1 text-[11px] font-semibold md:text-xs bg-muted text-muted-foreground">
                    <ShieldCheck className="h-3.5 w-3.5" />
                    {coach.requestStatus ? statusLabel[coach.requestStatus] : "-¦stek g+Ânderilmedi"}
                  </p>
                </div>

                <div className="flex w-full gap-2 sm:w-auto">
                  {coach.requestStatus !== "PENDING" && coach.requestStatus !== "ACCEPTED" ? (
                    <Button
                      type="button"
                      className="w-full sm:w-auto"
                      disabled={loadingCoachId === coach.id}
                      onClick={() => requestCoach(coach.id)}
                    >
                      {coach.requestStatus === "REJECTED" ? "Tekrar -¦stek G+Ânder" : "-¦stek G+Ânder"}
                    </Button>
                  ) : null}

                  {coach.requestStatus === "ACCEPTED" ? (
                    <ActionMenu
                      items={[
                        {
                          label: "Ba-ƒlant-¦y-¦ Kald-¦r",
                          danger: true,
                          onClick: () => {
                            void disconnectCoach(coach.id);
                          }
                        }
                      ]}
                    />
                  ) : null}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

import Link from "next/link";
import { ArrowRight, CalendarClock, MessageSquare, PlayCircle, ShieldCheck, Users } from "lucide-react";

import { prisma } from "@/lib/prisma";
import { auth } from "@/lib/auth";
import { getCurrentDayStart } from "@/lib/current-date";

export default async function ClientDashboardPage() {
  const session = await auth();
  const clientId = session?.user.id || "";

  const [assignments, workouts, comments, relations, inProgressWorkout] = await Promise.all([
    prisma.templateAssignment.findMany({
      where: { clientId },
      include: {
        template: {
          include: {
            exercises: {
              include: {
                exercise: true
              },
              orderBy: {
                order: "asc"
              }
            }
          }
        },
        workouts: {
          select: { status: true }
        }
      },
      orderBy: { createdAt: "desc" }
    }),
    prisma.workout.findMany({
      where: { clientId, status: { in: ["COMPLETED", "ABANDONED"] } },
      include: { template: true },
      orderBy: { startedAt: "desc" },
      take: 6
    }),
    prisma.comment.findMany({
      where: { workout: { clientId } },
      include: { author: true },
      orderBy: { createdAt: "desc" },
      take: 4
    }),
    prisma.coachClientRelation.findMany({
      where: { clientId, status: "ACCEPTED" },
      include: { coach: true },
      orderBy: { createdAt: "desc" }
    }),
    prisma.workout.findFirst({
      where: { clientId, status: "IN_PROGRESS" },
      include: { template: true },
      orderBy: { startedAt: "desc" }
    })
  ]);

  const today = getCurrentDayStart();

  const assignmentItems = assignments.map((assignment: (typeof assignments)[number]) => {
    const scheduledFor = new Date(assignment.scheduledFor);
    scheduledFor.setHours(0, 0, 0, 0);

    const isConsumed = assignment.isOneTime && assignment.workouts.some((workout: { status: "IN_PROGRESS" | "COMPLETED" | "ABANDONED" }) =>
      workout.status === "COMPLETED" || workout.status === "ABANDONED"
    );

    return {
      ...assignment,
      isToday: scheduledFor.toDateString() === today.toDateString(),
      isPast: scheduledFor.getTime() < today.getTime(),
      isConsumed
    };
  }).filter((assignment: { isPast: boolean; isConsumed: boolean }) => !assignment.isPast && !assignment.isConsumed);

  

  const todayAssignments = assignmentItems.filter((assignment: DashboardAssignment) => assignment.isToday);
  const upcomingAssignments = assignmentItems.filter((assignment: DashboardAssignment) => !assignment.isToday);

  type DashboardAssignment = (typeof assignmentItems)[number];

const groupAssignmentsByDate = (items: DashboardAssignment[]) => {
  return items.reduce<Record<string, DashboardAssignment[]>>((acc, assignment) => {
    
    const d = new Date(assignment.scheduledFor);
    const dateKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;

    if (!acc[dateKey]) acc[dateKey] = [];
    acc[dateKey].push(assignment);
    return acc;
  }, {} as Record<string, DashboardAssignment[]>);
};

  const renderCalendarGroups = (items: DashboardAssignment[], showStartButton: boolean) => {
    const groups = groupAssignmentsByDate(items);
    const keys = Object.keys(groups).sort((a, b) => a.localeCompare(b));

    return (
      <div className="space-y-3 md:space-y-4">
        {keys.map((dateKey) => {
          const date = new Date(dateKey);
          const dayItems = groups[dateKey] || [];

          return (
            <div key={dateKey} className="rounded-2xl border bg-card p-3 shadow-sm md:p-4">
              <div className="mb-3 flex flex-wrap items-center justify-between gap-2 border-b pb-2">
                <p className="text-xs font-semibold uppercase tracking-[0.18em] text-emerald-700 md:text-sm md:tracking-[0.2em]">
                  {date.toLocaleDateString("tr-TR", { weekday: "long" })}
                </p>
                <p className="text-base font-black text-foreground md:text-lg">
                  {date.toLocaleDateString("tr-TR", { day: "2-digit", month: "long" })}
                </p>
              </div>

              <div className="space-y-2">
                {dayItems.map((assignment) => {
                  const weightItems = assignment.template.exercises.filter(
                    (item: (typeof assignment.template.exercises)[number]) => item.exercise.type === "WEIGHT"
                  );
                  const cardioItems = assignment.template.exercises.filter(
                    (item: (typeof assignment.template.exercises)[number]) => item.exercise.type === "CARDIO"
                  );

                  return (
                    <div key={assignment.id} className="rounded-xl border p-3 md:p-4">
                      <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between sm:gap-3">
                        <div className="min-w-0">
                          <p className="line-clamp-2 text-sm font-bold text-foreground sm:text-base">{assignment.template.name}</p>
                          <p className="text-[11px] text-muted-foreground md:text-xs">
                            Atama: {new Date(assignment.createdAt).toLocaleDateString("tr-TR")}
                          </p>
                        </div>
                        {showStartButton ? (
                          <Link href={`/client/workout/${assignment.id}/start`} className="inline-flex w-full items-center justify-center rounded-full bg-emerald-600 px-4 py-2 text-sm font-medium text-white hover:bg-emerald-700 sm:w-auto">
                            Basla
                          </Link>
                        ) : (
                          <span className="inline-flex w-fit rounded-full bg-muted px-3 py-1 text-xs font-medium text-muted-foreground">
                            Gunu gelmedi
                          </span>
                        )}
                      </div>

                      <div className="mt-3 grid gap-2 md:grid-cols-2 md:gap-3">
                        <div className="rounded-lg bg-slate-50 p-2">
                          <p className="text-[11px] font-semibold uppercase tracking-[0.14em] text-slate-600">Agirlik ({weightItems.length})</p>
                          <div className="mt-1 space-y-1">
                            {weightItems.length === 0 ? (
                              <p className="text-xs text-muted-foreground">Yok</p>
                            ) : (
                              weightItems.map((item) => (
                                <p key={item.id} className="text-xs text-slate-700">
                                  {item.exercise.name}: {item.targetSets ?? "-"}x{item.targetReps ?? "-"} RIR {item.targetRir ?? "-"}
                                </p>
                              ))
                            )}
                          </div>
                        </div>
                        <div className="rounded-lg bg-orange-50 p-2">
                          <p className="text-[11px] font-semibold uppercase tracking-[0.14em] text-orange-700">Kardiyo ({cardioItems.length})</p>
                          <div className="mt-1 space-y-1">
                            {cardioItems.length === 0 ? (
                              <p className="text-xs text-muted-foreground">Yok</p>
                            ) : (
                              cardioItems.map((item) => (
                                <p key={item.id} className="text-xs text-orange-900">
                                  {item.exercise.name}: {item.durationMinutes ?? 1} dk / {(item.protocol as unknown[] | null)?.length ?? 0} blok
                                </p>
                              ))
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 md:space-y-8">
      <section className="overflow-hidden rounded-2xl border border-emerald-200/60 bg-gradient-to-br from-emerald-50 via-white to-lime-50 p-4 shadow-sm md:rounded-[32px] md:p-6">
        {/* <div className="flex flex-col gap-5 lg:flex-row lg:items-end lg:justify-between">
          <div className="grid grid-cols-2 gap-2 sm:grid-cols-4 sm:gap-3">
            <div className="rounded-2xl bg-white px-3 py-2.5 shadow-sm md:px-4 md:py-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500 md:text-xs md:tracking-[0.18em]">Aktif Coach</p>
              <p className="mt-1 text-2xl font-black text-slate-900 md:mt-2 md:text-3xl">{relations.length}</p>
            </div>
            <div className="rounded-2xl bg-white px-3 py-2.5 shadow-sm md:px-4 md:py-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500 md:text-xs md:tracking-[0.18em]">Atanm-¦+ƒ Plan</p>
              <p className="mt-1 text-2xl font-black text-slate-900 md:mt-2 md:text-3xl">{assignments.length}</p>
            </div>
            <div className="rounded-2xl bg-white px-3 py-2.5 shadow-sm md:px-4 md:py-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500 md:text-xs md:tracking-[0.18em]">Tamamlanan</p>
              <p className="mt-1 text-2xl font-black text-slate-900 md:mt-2 md:text-3xl">{workouts.length}</p>
            </div>
            <div className="rounded-2xl bg-white px-3 py-2.5 shadow-sm md:px-4 md:py-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-slate-500 md:text-xs md:tracking-[0.18em]">Yorum</p>
              <p className="mt-1 text-2xl font-black text-slate-900 md:mt-2 md:text-3xl">{comments.length}</p>
            </div>
          </div>
        </div> */}

        <div className="mt-4 grid gap-3 md:mt-6 md:grid-cols-3">
          <Link href={inProgressWorkout ? `/client/workout/${inProgressWorkout.assignmentId}/start` : "/client/workouts"} className="rounded-2xl bg-emerald-600 p-4 text-white shadow-sm transition hover:bg-emerald-700 md:rounded-3xl md:p-5">
            <div className="flex items-center justify-between">
              <PlayCircle className="h-6 w-6" />
              <ArrowRight className="h-5 w-5" />
            </div>
            <p className="mt-4 text-base font-bold md:mt-6 md:text-lg">{inProgressWorkout ? "Aktif antrenmana d+Ân" : "Ge+ºmi+ƒ antrenmanlara git"}</p>
            <p className="mt-1 text-xs text-emerald-50 md:mt-2 md:text-sm">
              {inProgressWorkout ? inProgressWorkout.template.name : "Tamamlanan t++m antrenmanlar-¦n-¦ listele."}
            </p>
          </Link>
          <Link href="/client/coaches" className="rounded-2xl border bg-white p-4 shadow-sm transition hover:border-emerald-300 hover:bg-emerald-50/60 md:rounded-3xl md:p-5">
            <Users className="h-6 w-6 text-emerald-600" />
            <p className="mt-4 text-base font-bold text-slate-900 md:mt-6 md:text-lg">Coach ba-ƒlant-¦lar-¦n-¦ y+Ânet</p>
            <p className="mt-1 text-xs text-slate-600 md:mt-2 md:text-sm">Yeni coach ara, bekleyen ili+ƒkileri kontrol et.</p>
          </Link>
          <Link href="/client/workouts" className="rounded-2xl border bg-white p-4 shadow-sm transition hover:border-emerald-300 hover:bg-emerald-50/60 md:rounded-3xl md:p-5">
            <CalendarClock className="h-6 w-6 text-emerald-600" />
            <p className="mt-4 text-base font-bold text-slate-900 md:mt-6 md:text-lg">Detayl-¦ ge+ºmi+ƒ</p>
            <p className="mt-1 text-xs text-slate-600 md:mt-2 md:text-sm">Set detaylar-¦ ve coach yorumlar-¦yla t++m ge+ºmi+ƒi a+º.</p>
          </Link>
        </div>
      </section>

      <section className="space-y-3">
        <div className="flex items-center justify-between gap-2">
          <h2 className="font-semibold">Atanm-¦+ƒ Template'ler</h2>
          <Link href="/client/workouts" className="text-sm font-medium text-emerald-700 hover:text-emerald-900">Ge+ºmi+ƒi a+º</Link>
        </div>
        {assignmentItems.length === 0 ? (
          <div className="rounded-xl border border-dashed p-6 text-sm text-muted-foreground">
            Bug++n veya gelecekte atanm-¦+ƒ aktif template yok.
          </div>
        ) : (
          <div className="space-y-5 md:space-y-6">
            <div>
              <h3 className="mb-3 text-sm font-semibold uppercase tracking-[0.2em] text-emerald-700">Bug++n</h3>
              {todayAssignments.length === 0 ? (
                <div className="rounded-2xl border border-dashed p-4 text-sm text-muted-foreground">Bug++ne atanm-¦+ƒ template yok.</div>
              ) : (
                renderCalendarGroups(todayAssignments, true)
              )}
            </div>

            <div>
              <h3 className="mb-3 text-sm font-semibold uppercase tracking-[0.2em] text-slate-600">Gelecek</h3>
              {upcomingAssignments.length === 0 ? (
                <div className="rounded-2xl border border-dashed p-4 text-sm text-muted-foreground">Gelecek g++nler i+ºin template yok.</div>
              ) : (
                renderCalendarGroups(upcomingAssignments, false)
              )}
            </div>
          </div>
        )}
      </section>

      <section className="grid gap-4 md:gap-6 xl:grid-cols-[1.2fr_0.8fr]">
        <div className="space-y-3">
          <div className="flex items-center justify-between gap-2">
            <h2 className="font-semibold">Son Antrenmanlar</h2>
            <Link href="/client/workouts" className="text-sm font-medium text-emerald-700 hover:text-emerald-900">T++m++n++ g+Âr</Link>
          </div>
        {workouts.length === 0 ? (
          <div className="rounded-xl border border-dashed p-6 text-sm text-muted-foreground">
            Hen++z tamamlanm-¦+ƒ antrenman yok.
          </div>
        ) : (
            <div className="space-y-2.5 md:space-y-3">
              {workouts.map((workout) => (
                <Link key={workout.id} href={`/client/workouts/${workout.id}`} className="flex items-center justify-between gap-3 rounded-2xl border bg-card p-3 shadow-sm transition hover:border-emerald-300 hover:bg-emerald-50/40 md:rounded-3xl md:p-4">
                  <div className="min-w-0">
                    <p className="line-clamp-1 font-semibold text-foreground">{workout.template.name}</p>
                    <p className="mt-1 text-xs text-muted-foreground md:text-sm">{new Date(workout.startedAt).toLocaleDateString("tr-TR")}</p>
                  </div>
                  <ArrowRight className="h-5 w-5 text-muted-foreground" />
                </Link>
              ))}
            </div>
        )}
        </div>

        <div className="space-y-3">
          <h2 className="font-semibold">Coach Yorumlar-¦</h2>
        {comments.length === 0 ? (
          <div className="rounded-xl border border-dashed p-6 text-sm text-muted-foreground">
            Hen++z coach yorumu yok.
          </div>
        ) : (
            comments.map((comment) => (
              <div key={comment.id} className="rounded-2xl border bg-card p-3 shadow-sm md:rounded-3xl md:p-4">
                <div className="flex items-start justify-between gap-3">
                  <MessageSquare className="mt-1 h-5 w-5 text-emerald-600" />
                  <div className="flex-1">
                    <p className="text-sm text-foreground md:text-sm">{comment.content}</p>
                    <p className="mt-2 text-xs text-muted-foreground">{comment.author.name}</p>
                  </div>
                </div>
              </div>
            ))
        )}
        </div>
      </section>

      <section className="grid gap-4 md:grid-cols-2">
        <div className="rounded-2xl border bg-card p-4 shadow-sm md:rounded-3xl md:p-5">
          <Users className="h-6 w-6 text-emerald-600" />
          <p className="mt-3 text-base font-bold md:mt-4 md:text-lg">Ba-ƒl-¦ coachlar</p>
          <p className="mt-2 text-sm text-muted-foreground">{relations.length > 0 ? relations.map((relation) => relation.coach.name).join(", ") : "Hen++z kabul edilmi+ƒ coach yok."}</p>
        </div>
      </section>
    </div>
  );
}

import Link from "next/link";
import { notFound } from "next/navigation";

import { AssignmentList } from "@/components/coach/AssignmentList";
import { AssignTemplateModal } from "@/components/coach/AssignTemplateModal";
import { CoachClientActionsMenu } from "@/components/coach/CoachClientActionsMenu";
import { WorkoutHistoryPanel } from "@/components/coach/WorkoutHistoryPanel";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

export default async function CoachClientDetailPage({ params }: { params: Promise<{ clientId: string }> }) {
  const session = await auth();
  const { clientId } = await params;
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const relation = await prisma.coachClientRelation.findFirst({
    where: {
      coachId: session?.user.id,
      clientId,
      status: "ACCEPTED"
    }
  });

  if (!relation) return notFound();

  const client = await prisma.user.findUnique({
    where: { id: clientId },
    include: {
      assignments: {
        where: {
          scheduledFor: {
            gte: today
          },
          workouts: {
            none: {}
          }
        },
        include: {
          template: true,
          _count: {
            select: {
              workouts: true
            }
          }
        },
        orderBy: { createdAt: "desc" }
      },
      workouts: {
        include: {
          template: true,
          sets: { include: { exercise: true }, orderBy: [{ exerciseId: "asc" }, { setNumber: "asc" }] },
          comments: { include: { author: true }, orderBy: { createdAt: "asc" } }
        },
        orderBy: { startedAt: "desc" },
        take: 10
      }
    }
  });

  if (!client) return notFound();

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-2xl font-bold">{client.name}</h1>
          <p className="text-sm text-muted-foreground">{client.email}</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <CoachClientActionsMenu clientId={client.id} />
          <AssignTemplateModal clientId={client.id} />
        </div>
      </div>

      <section className="space-y-2">
        <h2 className="font-semibold">Atanm-¦+ƒ Template'ler</h2>
        <AssignmentList
          assignments={client.assignments.map((assignment) => ({
            id: assignment.id,
            templateId: assignment.templateId,
            templateName: assignment.template.name,
            createdAt: assignment.createdAt.toISOString(),
            scheduledFor: assignment.scheduledFor.toISOString(),
            workoutsCount: assignment._count.workouts
          }))}
        />
      </section>

      <section className="space-y-2">
        <h2 className="font-semibold">Ge+ºmi+ƒ Antrenmanlar</h2>
        <WorkoutHistoryPanel workouts={client.workouts.map((workout) => ({
          id: workout.id,
          startedAt: workout.startedAt.toISOString(),
          finishedAt: workout.finishedAt ? workout.finishedAt.toISOString() : null,
          durationMinutes: workout.finishedAt ? Math.round((workout.finishedAt.getTime() - workout.startedAt.getTime()) / 60000) : null,
          status: workout.status,
          template: { name: workout.template.name },
          sets: workout.sets.map((setItem) => ({
            id: setItem.id,
            setNumber: setItem.setNumber,
            weightKg: setItem.weightKg,
            reps: setItem.reps,
            rir: setItem.rir,
            durationMinutes: setItem.durationMinutes,
            completed: setItem.completed,
            exercise: { name: setItem.exercise.name, type: setItem.exercise.type }
          })),
          comments: workout.comments.map((comment) => ({
            id: comment.id,
            content: comment.content,
            createdAt: comment.createdAt.toISOString(),
            author: { name: comment.author.name }
          }))
        }))} />
      </section>
    </div>
  );
}

import { ProgressCharts } from "@/components/coach/ProgressCharts";
import { prisma } from "@/lib/prisma";
import { notFound } from "next/navigation";

export default async function ClientProgressPage({
