      <div className="space-y-4">
        <h1 className="text-2xl font-bold">-¦lerleme Grafi-ƒi</h1>
        <div className="p-8 bg-gray-50 rounded-lg text-center dark:bg-gray-800">
          <p className="text-gray-500 dark:text-gray-400">
            Hen++z bu m+++ƒteri taraf-¦ndan tamamlanan antrenman bulunmamaktad-¦r
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <h1 className="text-2xl font-bold">-¦lerleme Grafi-ƒi</h1>
      <ProgressCharts clientId={clientId} exercises={exercises} />
    </div>
  );
}

