          >
            Kay-¦t Ol
          </Link>
        </div>
      </>
    );
  }

  return (
    <>
      {/* Desktop nav */}
      <nav className="ml-4 hidden items-center gap-0.5 lg:flex">
        {links.map(({ href, label, icon: Icon }) => (
          <Link key={href} href={href} className={getLinkClass(href)}>
            <Icon className="h-4 w-4 flex-shrink-0" />
            {label}
          </Link>
